import os
import numpy as np
import cv2
import pickle
from flask import Flask, request, jsonify
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
import face_recognition

app = Flask(__name__)

# Global variables
model = None
label_encoder = None
known_encodings = []
known_names = []

def load_employee_photos(directory):
    """Load and encode employee photos"""
    encodings = []
    names = []
    
    for filename in os.listdir(directory):
        if filename.lower().endswith(('.png', '.jpg', '.jpeg')):
            # Extract name from filename (assuming filename format: name.jpg)
            name = os.path.splitext(filename)[0]
            
            # Load image
            image_path = os.path.join(directory, filename)
            image = face_recognition.load_image_file(image_path)
            
            # Find face locations and encode
            face_locations = face_recognition.face_locations(image)
            
            if len(face_locations) > 0:
                face_encoding = face_recognition.face_encodings(image, face_locations)[0]
                encodings.append(face_encoding)
                names.append(name)
    
    return encodings, names

def train_model():
    """Train the facial recognition model"""
    global model, label_encoder, known_encodings, known_names
    
    # Load employee photos
    encodings, names = load_employee_photos('employee_photos')
    
    if len(encodings) == 0:
        raise Exception("No employee photos found")
    
    # Save known encodings and names
    known_encodings = encodings
    known_names = names
    
    # Encode labels
    label_encoder = LabelEncoder()
    encoded_labels = label_encoder.fit_transform(names)
    
    # Train SVM model
    model = SVC(probability=True, kernel='linear')
    model.fit(encodings, encoded_labels)

def get_face_encodings(image_path):
    """Get face encodings from image"""
    image = face_recognition.load_image_file(image_path)
    face_locations = face_recognition.face_locations(image)
    face_encodings = face_recognition.face_encodings(image, face_locations)
    return face_encodings

@app.route('/train', methods=['POST'])
def train():
    """Train the model with employee photos"""
    try:
        train_model()
        return jsonify({"status": "success", "message": "Model trained successfully"})
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

@app.route('/recognize', methods=['POST'])
def recognize():
    """Recognize faces in uploaded image"""
    global model, label_encoder, known_encodings, known_names
    
    if model is None:
        return jsonify({"status": "error", "message": "Model not trained yet"}), 400
    
    try:
        # Get uploaded file
        if 'image' not in request.files:
            return jsonify({"status": "error", "message": "No image provided"}), 400
        
        file = request.files['image']
        if file.filename == '':
            return jsonify({"status": "error", "message": "No image selected"}), 400
        
        # Save temporary file
        import tempfile
        import uuid
        temp_filename = os.path.join(tempfile.gettempdir(), f"{uuid.uuid4()}.jpg")
        file.save(temp_filename)
        
        # Get face encodings from image
        face_encodings = get_face_encodings(temp_filename)
        
        # Clean up temp file
        os.remove(temp_filename)
        
        if len(face_encodings) == 0:
            return jsonify({"status": "error", "message": "No faces detected in image"}), 400
        
        # Get predictions
        predictions = []
        for face_encoding in face_encodings:
            # Predict
            face_distances = face_recognition.face_distance(known_encodings, face_encoding)
            min_distance = np.min(face_distances)
            
            # Get probabilities
            probabilities = model.predict_proba([face_encoding])[0]
            
            # Create result dictionary
            result = {
                "face_detected": True,
                "confidence_score": float(1 - min_distance) if min_distance < 1 else 0.0,
                "probabilities": {}
            }
            
            # Add probability for each known face
            for i, name in enumerate(known_names):
                result["probabilities"][name] = float(probabilities[i])
            
            predictions.append(result)
        
        return jsonify({
            "status": "success",
            "predictions": predictions
        })
        
    except Exception as e:
        return jsonify({"status": "error", "message": str(e)}), 500

@app.route('/status', methods=['GET'])
def status():
    """Check model status"""
    global model, known_names
    return jsonify({
        "model_trained": model is not None,
        "known_faces_count": len(known_names),
        "known_faces": known_names
    })

if __name__ == '__main__':
    # Train model on startup
    try:
        train_model()
        print("Model trained successfully")
    except Exception as e:
        print(f"Failed to train model: {e}")
    
    app.run(host='0.0.0.0', port=5000, debug=False)